// biome-ignore lint/style/useFilenamingConvention: Remotion requires PascalCase entry point

import { Composition, Still } from "@vendor/remotion";
import type React from "react";
import { BlogFeaturedBase } from "./compositions/blog-featured-base";
import { BlogFeaturedConcentric } from "./compositions/blog-featured-concentric";
import { BlogFeaturedCross } from "./compositions/blog-featured-cross";
import { BlogFeaturedDuo } from "./compositions/blog-featured-duo";
import { BlogFeaturedGhost } from "./compositions/blog-featured-ghost";
import { BlogFeaturedLissajous } from "./compositions/blog-featured-lissajous";
import { BlogFeaturedRule } from "./compositions/blog-featured-rule";
import { BlogFeaturedTrail } from "./compositions/blog-featured-trail";
import { ChangelogV010Events } from "./compositions/changelog-v010-events";
import { ChangelogV010Featured } from "./compositions/changelog-v010-featured";
import { GitHubBanner } from "./compositions/github-banner";
import { LandingHero } from "./compositions/landing-hero/landing-hero";
import { Logo } from "./compositions/logo";
import { TwitterBanner } from "./compositions/twitter-banner";
import { MANIFEST } from "./manifest";

// Component registry — maps manifest component names to actual React components
const COMPONENTS: Record<string, React.FC<Record<string, unknown>>> = {
  BlogFeaturedBase,
  BlogFeaturedConcentric,
  BlogFeaturedCross,
  BlogFeaturedDuo,
  BlogFeaturedGhost,
  BlogFeaturedLissajous,
  BlogFeaturedRule,
  BlogFeaturedTrail,
  ChangelogV010Events,
  ChangelogV010Featured,
  LandingHero,
  Logo,
  TwitterBanner,
  GitHubBanner,
};

export const RemotionRoot = () => {
  return (
    <>
      {Object.entries(MANIFEST.compositions).map(([id, entry]) => {
        const Component = COMPONENTS[entry.component];
        if (!Component) {
          throw new Error(`No component registered for composition "${id}"`);
        }

        if (entry.type === "video") {
          return (
            <Composition
              component={Component}
              durationInFrames={entry.durationInFrames}
              fps={entry.fps}
              height={entry.height}
              id={id}
              key={id}
              width={entry.width}
            />
          );
        }

        return (
          <Still
            component={Component}
            defaultProps={entry.props}
            height={entry.height}
            id={id}
            key={id}
            width={entry.width}
          />
        );
      })}
    </>
  );
};

/**
 * Composition Manifest — Single Source of Truth
 *
 * To add a new composition:
 * 1. Create the component in src/compositions/<name>/<name>.tsx
 * 2. Add a COMPONENTS entry in Root.tsx
 * 3. Add the composition definition here with its output targets
 * 4. Run: pnpm render:all
 *
 * The manifest drives:
 * - Root.tsx registration (Composition/Still elements)
 * - Rendering (format, scale, codec)
 * - Distribution (auto-copy to destination directories)
 * - Post-processing (favicon.ico bundling)
 */
import type { RenderMediaOptions } from "@vendor/remotion/renderer";

// ── Types ────────────────────────────────────────────────────────────

interface OutputTarget {
  /** Destination directory (relative to monorepo root) */
  dest: string;
  /** Filename override (defaults to `${compositionId}.${format}`) */
  filename?: string;
  /** Output format */
  format: "png" | "webp" | "webm";
  /** For stills extracted from video compositions: which frame to capture */
  frame?: number;
  /** Render scale factor (default: 1) */
  scale?: number;
}

interface StillComposition {
  /** Component name in the COMPONENTS registry in Root.tsx */
  component: string;
  height: number;
  outputs: OutputTarget[];
  props?: Record<string, unknown>;
  type: "still";
  width: number;
}

interface VideoComposition {
  /** Component name in the COMPONENTS registry in Root.tsx */
  component: string;
  durationInFrames: number;
  fps: number;
  height: number;
  outputs: OutputTarget[];
  renderProfile: Pick<
    RenderMediaOptions,
    "codec" | "imageFormat" | "scale" | "everyNthFrame" | "numberOfGifLoops"
  >;
  type: "video";
  width: number;
}

export type CompositionEntry = StillComposition | VideoComposition;

interface PostProcess {
  /** Where to write the .ico */
  dests: string[];
  filename: string;
  /** Composition IDs whose outputs feed into this post-process */
  sources: string[];
  type: "ico";
}

export interface CompositionManifest {
  compositions: Record<string, CompositionEntry>;
  postProcess: PostProcess[];
}

