1	import type { Bounds, Polygon, Vec2 } from "./types";
2	
3	// ── Constants ────────────────────────────────────────────
4	const COS30 = Math.cos(Math.PI / 6); // √3/2 ≈ 0.866
5	const SIN30 = 0.5;
6	const EPS = 1e-9;
7	
8	// ── Isometric projection ─────────────────────────────────
9	// x-axis → right-downward at 30°
10	// y-axis → left-downward at 30°
11	// z-axis → straight up
12	export function project(x: number, y: number, z: number): Vec2 {
13	  return [(x - y) * COS30, (x + y) * SIN30 - z];
14	}
15	
16	// ── Signed area ──────────────────────────────────────────
17	// Positive = CW in screen coords (y-down). Negative = CCW.
18	export function signedArea(p: Polygon): number {
19	  let a = 0;
20	  const n = p.length;
21	  for (let i = 0; i < n; i++) {
22	    const pi = p[i];
23	    const pj = p[(i + 1) % n];
24	    if (!(pi && pj)) {
25	      continue;
26	    }
27	    a += pi[0] * pj[1] - pj[0] * pi[1];
28	  }
29	  return a * 0.5;
30	}
31	
32	// ── Winding helpers ──────────────────────────────────────
33	export function ensureCW(p: Polygon): Polygon {
34	  return signedArea(p) < 0 ? [...p].reverse() : p;
35	}
36	
37	function ensureCCW(p: Polygon): Polygon {
38	  return signedArea(p) > 0 ? [...p].reverse() : p;
39	}
40	
41	// ── Edge side test ───────────────────────────────────────
42	// Positive → p is to the right of directed edge a→b (screen coords, y-down)
43	function side(a: Vec2, b: Vec2, p: Vec2): number {
44	  return (b[0] - a[0]) * (p[1] - a[1]) - (b[1] - a[1]) * (p[0] - a[0]);
45	}
46	
47	// ── Line–line intersection ───────────────────────────────
48	function lineHit(p1: Vec2, p2: Vec2, p3: Vec2, p4: Vec2): Vec2 | null {
49	  const dx1 = p2[0] - p1[0],
50	    dy1 = p2[1] - p1[1];
51	  const dx2 = p4[0] - p3[0],
52	    dy2 = p4[1] - p3[1];
53	  const cross = dx1 * dy2 - dy1 * dx2;
54	  if (Math.abs(cross) < EPS) {
55	    return null;
56	  }
57	  const dx3 = p3[0] - p1[0],
58	    dy3 = p3[1] - p1[1];
59	  const t = (dx3 * dy2 - dy3 * dx2) / cross;
60	  return [p1[0] + t * dx1, p1[1] + t * dy1];
61	}
62	
63	// ── Sutherland-Hodgman polygon clipping ──────────────────
64	// Clips `subject` against convex `clip`. Both must be CW (screen).
65	// Returns intersection polygon (CW) or empty array.
66	export function clipPolygon(subject: Polygon, clip: Polygon): Polygon {
67	  if (subject.length === 0 || clip.length === 0) {
68	    return [];
69	  }
70	  let out: Vec2[] = [...subject];
71	
72	  for (let i = 0, cn = clip.length; i < cn; i++) {
73	    if (out.length === 0) {
74	      return [];
75	    }
76	    const inp = [...out];
77	    out = [];
78	    const a = clip[i];
79	    const b = clip[(i + 1) % cn];
80	    if (!(a && b)) {
81	      continue;
82	    }
83	
84	    for (let j = 0, sn = inp.length; j < sn; j++) {
85	      const cur = inp[j];
86	      const prev = inp[(j + sn - 1) % sn];
87	      if (!(cur && prev)) {
88	        continue;
89	      }
90	      const curIn = side(a, b, cur) >= -EPS;
91	      const prevIn = side(a, b, prev) >= -EPS;
92	
93	      if (curIn) {
94	        if (!prevIn) {
95	          const h = lineHit(prev, cur, a, b);
96	          if (h) {
97	            out.push(h);
98	          }
99	        }
100	        out.push(cur);
101	      } else if (prevIn) {
102	        const h = lineHit(prev, cur, a, b);
103	        if (h) {
104	          out.push(h);
105	        }
106	      }
107	    }
108	  }
109	  return out;
110	}
111	
112	// ── Point-in-polygon (ray cast) ──────────────────────────
113	function _pointInPolygon(pt: Vec2, poly: Polygon): boolean {
114	  let inside = false;
115	  for (let i = 0, j = poly.length - 1; i < poly.length; j = i++) {
116	    const pi = poly[i];
117	    const pj = poly[j];
118	    if (!(pi && pj)) {
119	      continue;
120	    }
121	    if (
122	      pi[1] > pt[1] !== pj[1] > pt[1] &&
123	      pt[0] < ((pj[0] - pi[0]) * (pt[1] - pi[1])) / (pj[1] - pi[1]) + pi[0]
124	    ) {
125	      inside = !inside;
126	    }
127	  }
128	  return inside;
129	}
130	
131	// ── SVG path generation ──────────────────────────────────
132	function polygonToPath(p: Polygon): string {
133	  if (p.length === 0) {
134	    return "";
135	  }
136	  return `${p
137	    .map(
138	      (v, i) => `${i === 0 ? "M" : "L"}${v[0].toFixed(2)},${v[1].toFixed(2)}`
139	    )
140	    .join(" ")} Z`;
141	}
142	
143	/** Builds an SVG path with even-odd holes */
144	export function faceToPath(contour: Polygon, holes: Polygon[]): string {
145	  const outer = polygonToPath(ensureCW(contour));
146	  if (holes.length === 0) {
147	    return outer;
148	  }
149	  const inner = holes.map((h) => polygonToPath(ensureCCW(h))).join(" ");
150	  return `${outer} ${inner}`;
151	}
152	
153	// ── Bounds ───────────────────────────────────────────────
154	export function polyBounds(p: Polygon): Bounds {
155	  let minX = Number.POSITIVE_INFINITY,
156	    minY = Number.POSITIVE_INFINITY,
157	    maxX = Number.NEGATIVE_INFINITY,
158	    maxY = Number.NEGATIVE_INFINITY;
159	  for (const v of p) {
160	    if (v[0] < minX) {
161	      minX = v[0];
162	    }
163	    if (v[0] > maxX) {
164	      maxX = v[0];
165	    }
166	    if (v[1] < minY) {
167	      minY = v[1];
168	    }
169	    if (v[1] > maxY) {
170	      maxY = v[1];
171	    }
172	  }
173	  return { minX, minY, maxX, maxY };
174	}
